        private void btnSearch_Click(object sender, EventArgs e)
        {
            if (comReport.Items.Count < 1) return;
            crvResult.ReportSource = null;
            crvResult.Refresh();
            tabControl1.TabPages.Remove(tabUser);
            removeTab("tabPer");
            tabControl1.SelectTab(tabPage1);
            btnExcel.Enabled = false;
            btnPdf.Enabled = false;
            if (comReport.Text == "" || comUser.Text == "")
            {
                MessageBox.Show("กรุณาเลือกรายงาน");
                return;
            }
            if (dgvResult.DataSource != null)
            {
                dgvResult.DataSource = null;
            }
            else
            {
                dgvResult.Rows.Clear();
                dgvResult.Columns.Clear();
            }
            Cursor = Cursors.WaitCursor;
            intSelectedIndex = intReportIndex[comReport.SelectedIndex];
            DateTime dst = dateStart.Value;
            DateTime dfn = dateFinish.Value;
            string strdst = dst.Year.ToString() + "-" + dst.ToString("MM'-'dd") + " " + timeStart.Value.ToLongTimeString();
            string strdfn = dfn.Year.ToString() + "-" + dfn.ToString("MM'-'dd") + " " + timeFinish.Value.ToLongTimeString();// + " 23:59:59";
            string sql = "";

            //Mac 2017/05/24
            var firstDayOfMonth = new DateTime(dst.Year, dst.Month, 1);
            var lastDayOfMonth = firstDayOfMonth.AddMonths(1).AddDays(-1);
            var firstDayOfMonthFn = new DateTime(dfn.Year, dfn.Month, 1);
            var lastDayOfMonthFn = firstDayOfMonthFn.AddMonths(1).AddDays(-1);

            //    MessageBox.Show(intSelectedIndex.ToString());

            btnUpdateReport.Visible = false; //Mac 2015/02/06

            if ((FormMain.pm.print.UseAsciiMem) && (txtCardID.Text.Trim().Length < 10) && (txtCardID.Text.Trim().Length > 0)) //Mac 2016/03/23
            {
                txtCardID.Text = (Convert.ToInt32(((int)Convert.ToChar(txtCardID.Text.Substring(0, 1))).ToString() + txtCardID.Text.Substring(1))).ToString();
            }

            switch (intSelectedIndex)
            {
                case 0:
                    sql = sqlReport();
                    break;
                case 1:
                    sql = sqlReport();
                    break;
                case 2:
                    /*sql = "SELECT user_record.no as ลำดับ,user.name as ชื่อเจ้าหน้าที่,"
                        + "case  when user_record.gate = 'I' then 'ขาเข้า' when user_record.gate = 'O' then 'ขาออก' when user_record.gate = 'B' then 'ขาเข้า/ขาออก' end as ประตู ,"
                        + "user_record.datein as เวลาเข้า,user_record.dateout as เวลาออก,user_record.price as รายได้,"
                        + "user_record.discount as ส่วนลด FROM ";
                    sql += "user,user_record";
                    sql += " WHERE user.id=user_record.id";
                    sql += " AND dateout BETWEEN '" + strdst + "' AND '" + strdfn + "'";
                    if (comUser.SelectedIndex > 0)
                    {
                        sql += " AND user_record.id =" + dicUserInt[comUser.Text];
                    }
                    sql += " ORDER BY user_record.no";*/
                    sql = "SELECT A.no as ลำดับ,C.name as ชื่อเจ้าหน้าที่,";
                    sql += "case  when A.gate = 'I' then 'ขาเข้า' when A.gate = 'O' then 'ขาออก' when A.gate = 'B' then 'ขาเข้า/ขาออก' end as ประตู,";
                    //sql += "A.datein as เวลาเข้า,A.dateout as เวลาออก,";
                    sql += "date_format(A.datein, '%d/%m/%Y %H:%i:%s') as เวลาเข้า,date_format(A.dateout, '%d/%m/%Y %H:%i:%s') as เวลาออก,"; //Mac 2018/12/21
                    sql += " CASE WHEN B.price > 0 THEN B.price ELSE 0 END as รายได้,";
                    sql += " CASE WHEN B.discount > 0 THEN B.discount ELSE 0 END as ส่วนลด FROM";
                    sql += " user C,user_record A";
                    sql += " LEFT JOIN(";
                    if (pm.print.NotShowNoString.Trim().Length > 0 && pm.user.Level == 0) //Mac 2022/04/22
                    {
                        sql += " SELECT SUM(recordout.price) AS price";
                        sql += " ,SUM(recordout.discount) AS discount";
                        sql += " ,recordout.userno FROM recordout left join recordin on recordout.no = recordin.no";
                        sql += " where recordin.notshow = 'N'";
                        sql += " GROUP BY recordout.userno) B";
                    }
                    else
                    {
                        sql += " SELECT SUM(price) AS price";
                        sql += " ,SUM(discount) AS discount";
                        sql += " ,userno FROM recordout";
                        sql += " GROUP BY userno) B";
                    }
                    sql += " ON A.no = B.userno";
                    sql += " WHERE C.id=A.id";
                    sql += " AND A.datein BETWEEN '" + strdst + "' AND '" + strdfn + "'";
                    if (comUser.SelectedIndex > 0)
                    {
                        sql += " AND A.id =" + dicUserInt[comUser.Text];
                    }
                    if (cobGuardhouse.SelectedIndex > 0) //Mac 2019/11/14
                        sql += " and A.guardhouse = '" + cobGuardhouse.Text + "' ";
                    sql += " ORDER BY A.no";

                    break;
                case 3:
                    //sql = "SELECT liftrecord.datelift as เวลายก,user.name as เจ้าหน้าที่,"
                    //sql = "SELECT liftrecord.no as ลำดับ, liftrecord.datelift as เวลายก,user.name as เจ้าหน้าที่," //Mac 2018/11/08
                    sql = "SELECT liftrecord.no as ลำดับ, date_format(liftrecord.datelift, '%d/%m/%Y %H:%i:%s') as เวลายก,user.name as เจ้าหน้าที่," //Mac 2018/12/21
                        + "case  when liftrecord.gate LIKE 'I%' then 'ขาเข้า' when liftrecord.gate LIKE 'O%' then 'ขาออก' when liftrecord.gate = 'B' then 'ขาเข้า/ขาออก' end as ประตู ,"
                        + "liftrecord.license as บันทึก FROM ";
                    sql += "user,liftrecord";
                    sql += " WHERE user.id=liftrecord.userid";
                    sql += " AND liftrecord.datelift BETWEEN '" + strdst + "' AND '" + strdfn + "'";
                    if (comUser.SelectedIndex > 0)
                    {
                        sql += " AND liftrecord.userid =" + dicUserInt[comUser.Text];
                    }

                    if (txtLicense.Text != "") //Mac 2018/06/30
                        sql += " AND liftrecord.license LIKE '%" + txtLicense.Text + "%'";

                    sql += " ORDER BY liftrecord.datelift";
                    Console.WriteLine(sql);
                    break;
                case 4:
                    sql = SQLCarIn();
                    break;
                case 5:
                    goto case 0;
                    //sql = SQLCardIn(); //2014/10/07
                    break;
                case 6:
                    sql = SQLReportDISTINCT();
                    break;
                case 7:
                    //sql = "SELECT liftrecord.datelift as เวลายก ,user.name as พนักงาน,"
                    sql = "SELECT date_format(liftrecord.datelift, '%d/%m/%Y %H:%i:%s') as เวลายก ,user.name as พนักงาน," //Mac 2018/
                        + "case  when liftrecord.gate LIKE 'I%' then 'ขาเข้า' when liftrecord.gate LIKE 'O%' then 'ขาออก' when liftrecord.gate = 'B' then 'ขาเข้า/ขาออก' end as ประตู ,"
                        + "liftrecord.license as บันทึก,liftrecord.picdiv,liftrecord.piclic FROM ";
                    //if (!pm.Use2Camera)
                    //    sql = "SELECT liftrecord.datelift as เวลายก ,user.name as พนักงาน,"
                    //        + "case  when liftrecord.gate = 'I' then 'ขาเข้า' when liftrecord.gate = 'O' then 'ขาออก' when liftrecord.gate = 'B' then 'ขาเข้า/ขาออก' end as ประตู,"
                    //        + "liftrecord.license,liftrecord.piclic FROM ";
                    sql += "user,liftrecord";
                    sql += " WHERE user.id=liftrecord.userid";
                    sql += " AND liftrecord.datelift BETWEEN '" + strdst + "' AND '" + strdfn + "'";
