                            "recordout.dateout AS 'เวลาออก',\r\n" +
                            "recordout.userout AS 'เจ้าหน้าที่ขาออก',\r\n" +
                            "recordout.proid AS 'E-Stamp',\r\n" +
                            "recordin.memo AS 'หมายเหตุ'\r\n" +
                            "from recordin left join recordout on recordin.no = recordout.no \r\n" +
                            "left join member on member.license like concat('%',recordin.license,'%')\r\n" +
                            "left join cardmf t1 on recordin.id = t1.name left join cardpx t2 on recordin.id = t2.name \r\n" +
                            "WHERE recordout.dateout BETWEEN '" + strdst + "' AND '" + strdfn + "' \r\n";

                        #region Condition
                        if (pm.print.NotShowNoString.Trim().Length > 0 && pm.user.Level == 0)
                            sql += " AND recordin.notshow = 'N'";

                        if (txtNameCard.Text.Trim().Length > 0)
                            sql += " AND (t1.name_on_card like '%" + txtNameCard.Text + "%' or t2.name_on_card like '%" + txtNameCard.Text + "%')";

                        if (comUser.SelectedIndex > 0)
                            sql += " AND recordout.userout =" + dicUserInt[comUser.Text];

                        if (FormMain.pm.print.ReportSearchMemGroup)
