                    else if (pm.UsePaymentRabbit)
                    {
                        sql += "CASE WHEN t3.qr IS NOT NULL AND t3.rabbit_id IS NOT NULL THEN 'PromptPay' WHEN t1.pay_type = 'EDC' THEN 'EDC' ELSE 'เงินสด' END AS 'ช่องทางการชำระเงิน',\n";
                        sql += "t3.qr as 'QR Code', t3.rabbit_id as 'rabbit ID'\n";
                        sql += "from recordout t1 left join recordin t2 on t1.no = t2.no ";
                        sql += "left join (select max(t1.no), t1.no_recordin, t1.rabbit_id, t1.status, t2.qr\n";
                        sql += "from rabbit_post t1 left join rabbit_get t2 on t1.rabbit_id = t2.rabbit_id where t1.status = 'Y' group by t1.no_recordin) t3 on t1.no = t3.no_recordin\n";
                    }
                    else if (pm.UsePaymentScb)
                    {
                        sql += "CASE WHEN t3.qr IS NOT NULL AND t3.scb_id IS NOT NULL THEN 'PromptPay' ELSE 'เงินสด' END AS 'ช่องทางการชำระเงิน',\n";
                        sql += "t3.qr as 'QR Code', t3.scb_id as 'SCB ID'\n";
                        sql += "from recordout t1 left join recordin t2 on t1.no = t2.no ";
                        sql += "left join (select max(t1.no), t1.no_recordin, t1.scb_id, t1.status, t2.qr\n";
                        sql += "from scb_post t1 left join scb_get t2 on t1.scb_id = t2.scb_id where t1.status = 'Y' group by t1.no_recordin) t3 on t1.no = t3.no_recordin\n";
                    }
                    sql += " WHERE t1.dateout BETWEEN '" + strdst + "' AND '" + strdfn + "'";
                    sql += " AND t1.price > 0"; //Mac 2024/06/10

                    if (comUser.SelectedIndex > 0)
                        sql += " AND t1.userout = " + dicUserInt[comUser.Text];
                    if (comPromotion.SelectedIndex > 0)
                        sql += " AND t1.proid =" + dicProNameInt[comPromotion.Text];
                    if (txtLicense.Text != "")
                        sql += " AND t2.license LIKE '%" + txtLicense.Text + "%'";
                    if (txtCardID.Text != "")
                        sql += " AND t2.id = " + txtCardID.Text;

                    if (cobChannel.SelectedIndex == 1)
                    {
                        if (pm.UsePaymentKsher)
                            sql += " AND t3.channel = 'PromptPay'";
                        else if (pm.UsePaymentBeam)
                            sql += " AND (CASE WHEN t3.qr IS NOT NULL AND t3.beam_id IS NOT NULL THEN 'PromptPay' WHEN t1.pay_type = 'EDC' THEN 'EDC' ELSE 'เงินสด' END) = 'PromptPay'";
                        else if (pm.UsePaymentRabbit)
                            sql += " AND (CASE WHEN t3.qr IS NOT NULL AND t3.rabbit_id IS NOT NULL THEN 'PromptPay' WHEN t1.pay_type = 'EDC' THEN 'EDC' ELSE 'เงินสด' END) = 'PromptPay'";
                        else if (pm.UsePaymentScb)
                            sql += " AND (CASE WHEN t3.qr IS NOT NULL AND t3.scb_id IS NOT NULL THEN 'PromptPay' ELSE 'เงินสด' END) = 'PromptPay'";
                    }
                    else if (cobChannel.SelectedIndex == 2)
                    {
                        sql += " AND t3.channel = 'TrueMoney'";
                    }
                    else if (cobChannel.SelectedIndex == 3)
                    {
                        if (pm.UsePaymentKsher)
                            sql += " AND t3.channel is null AND t1.pay_type = 'C'";
                        else if (pm.UsePaymentRabbit)
                            sql += " AND (CASE WHEN t3.qr IS NOT NULL AND t3.rabbit_id IS NOT NULL THEN 'PromptPay' WHEN t1.pay_type = 'EDC' THEN 'EDC' ELSE 'เงินสด' END) = 'เงินสด'";
                        else if (pm.UsePaymentBeam)
                            sql += " AND (CASE WHEN t3.qr IS NOT NULL AND t3.beam_id IS NOT NULL THEN 'PromptPay' WHEN t1.pay_type = 'EDC' THEN 'EDC' ELSE 'เงินสด' END) = 'เงินสด'";
                        else if (pm.UsePaymentScb)
                            sql += " AND (CASE WHEN t3.qr IS NOT NULL AND t3.scb_id IS NOT NULL THEN 'PromptPay' ELSE 'เงินสด' END) = 'เงินสด'";
                    }
                    else if (cobChannel.SelectedIndex == 4)
                    {
                        if (pm.UsePaymentKsher)
                            sql += " AND t3.channel is null AND t1.pay_type = 'EDC'";
                        else if (pm.UsePaymentRabbit)
                            sql += " AND (CASE WHEN t3.qr IS NOT NULL AND t3.rabbit_id IS NOT NULL THEN 'PromptPay' WHEN t1.pay_type = 'EDC' THEN 'EDC' ELSE 'เงินสด' END) = 'EDC'";
                        else if (pm.UsePaymentBeam)
                            sql += " AND (CASE WHEN t3.qr IS NOT NULL AND t3.beam_id IS NOT NULL THEN 'PromptPay' WHEN t1.pay_type = 'EDC' THEN 'EDC' ELSE 'เงินสด' END) = 'EDC'";
                        else if (pm.UsePaymentScb)
                            sql += " AND (CASE WHEN t3.qr IS NOT NULL AND t3.scb_id IS NOT NULL THEN 'PromptPay' ELSE 'เงินสด' END) = 'EDC'";
                    }

                    sql += " ORDER BY t1.dateout";
                    break;
                case 163:
                    int selectedYear = dateStart.Value.Year;
                            sql = $@"
                    SELECT 
                        license,
                        COUNT(*) AS license_count,
                        MONTH(datein) AS month_no
                    FROM recordin
                    WHERE datein BETWEEN '{selectedYear}-01-01 00:00:00' AND '{selectedYear}-12-31 23:59:59'
                    GROUP BY license, MONTH(datein)
                    ORDER BY MONTH(datein);";
                break;
            
        }
            if (intSelectedIndex == 13)
            {
                strHead = "รายงาน" + comReport.Text + " จากวันที่ "
                  + dateStart.Value.ToLongDateString()
                  + " เวลา " + timeStart.Value.ToLongTimeString()
