                    + dateStart.Value.ToLongDateString()
                    + " เวลา 0:00:00"
                    + " ถึงวันที่ " + dateStart.Value.ToLongDateString()
                    + " เวลา 23:59:59";
            }
            else if ((intSelectedIndex == 33) || (intSelectedIndex == 38))
            {
