                            + " เวลา " + timeStart.Value.ToLongTimeString()
                            + " ถึงวันที่ " + dateFinish.Value.ToLongDateString()
                            + " เวลา " + timeFinish.Value.ToLongTimeString();
                    }
                }
            }

            strHead = strHead.Replace("รายงานรายงาน", "รายงาน"); //Mac 2019/05/14

            lbHead.Text = strHead;
            dgvResult.Visible = false;
            Display(sql);
