        private DataTable ConvertToEstampWithRemark(DataTable dt)
        {
            DataTable convertedDataTable = new DataTable();

            convertedDataTable.Columns.Add(new DataColumn("ลำดับ", typeof(string)));
            convertedDataTable.Columns.Add(new DataColumn("ประเภท", typeof(string)));
            convertedDataTable.Columns.Add(new DataColumn("ทะเบียน", typeof(string)));
            convertedDataTable.Columns.Add(new DataColumn("เวลาเข้า", typeof(string)));
            convertedDataTable.Columns.Add(new DataColumn("เจ้าหน้าที่ขาเข้า", typeof(string)));
            convertedDataTable.Columns.Add(new DataColumn("เวลาออก", typeof(string)));
            convertedDataTable.Columns.Add(new DataColumn("เจ้าหน้าที่ขาออก", typeof(string)));
            convertedDataTable.Columns.Add(new DataColumn("E-Stamp", typeof(string)));
            convertedDataTable.Columns.Add(new DataColumn("หมายเหตุ", typeof(string)));

            foreach (DataRow row in dt.Rows)
            {
                string convertedCarType = dicCarTypeStr.TryGetValue(Convert.ToInt16(row["ประเภทรถ"]), out string carType) ? carType : string.Empty;
                string convertedUserIn = dicUserStr.TryGetValue(Convert.ToInt16(row["เจ้าหน้าที่ขาเข้า"]), out string userIn) ? userIn : string.Empty;
                string convertedUserOut = dicUserStr.TryGetValue(Convert.ToInt16(row["เจ้าหน้าที่ขาออก"]), out string userOut) ? userOut : string.Empty;
                string convertedEstamp = dicProNameStr.TryGetValue(Convert.ToInt16(row["E-Stamp"]), out string estamp) ? estamp : string.Empty;
                
                DataRow newRow = convertedDataTable.NewRow();
                newRow["ลำดับ"] = row["หมายเลขรายการ"]?.ToString();
                newRow["ประเภท"] = convertedCarType;
                newRow["ทะเบียน"] = row["ทะเบียนรถ"]?.ToString();
                newRow["เวลาเข้า"] = row["เวลาเข้า"]?.ToString();
                newRow["เจ้าหน้าที่ขาเข้า"] = convertedUserIn;
                newRow["เวลาออก"] = row["เวลาออก"]?.ToString();
                newRow["เจ้าหน้าที่ขาออก"] = convertedUserOut;
                newRow["E-Stamp"] = convertedEstamp;
                newRow["หมายเหตุ"] = row["หมายเหตุ"]?.ToString();

                convertedDataTable.Rows.Add(newRow);
            }

            return convertedDataTable;
        }

        private DataTable FilterParkedOverdate(DataTable dt) /* รายงานรถออกเกินเวลา */
        {
            var query = dt.AsEnumerable()
                .Where(row =>
                {
                    bool hasEntry = DateTime.TryParse(row["เวลาเข้า"]?.ToString(), out DateTime entryTime);
                    bool hasExit = DateTime.TryParse(row["เวลาออก"]?.ToString(), out DateTime exitTime);

                    if (!hasEntry || !hasExit)
                        return false;

                    return entryTime.Date != exitTime.Date;
                });

            if (query.Any())
                return query.CopyToDataTable();

            return dt.Clone();
        }


