                    float floT = (float)intT;
                    //double floV = floT * 0.07;                    
                    double floBV = (floT * 100) / 107;
                    floBV = Math.Round(floBV, 2);
                    double floV = floT - floBV;
                    dgvResult[10, i].Value = floBV.ToString("#0.00");
                    dgvResult[11, i].Value = floV.ToString("#0.00");
                    intSumR += intR;
                    intSumD += intD;
                    intSumT += intT;
                    intSumBV += floBV;
                    intSumV += floV;
