        private string SQLReportGroupPrice()
        {
            string sql = "SELECT recordout.no, recordin.license, recordin.datein, recordin.userin, recordout.dateout, recordout.userout, " +
                         "recordout.price, recordout.discount, recordout.userout, recordout.userout, recordout.userout, " +
                         "recordin.cartype, recordout.proid";

            if (pm.print.UseMemLicensePlate) // Match by license
            {
                sql += " FROM recordin LEFT JOIN recordout ON recordin.no = recordout.no " +
                       "LEFT JOIN member ON member.license LIKE CONCAT('%', recordin.license, '%')";
            }
            else // Match by cardid
            {
                sql += " FROM recordin LEFT JOIN recordout ON recordin.no = recordout.no " +
                       "LEFT JOIN member ON recordin.id = member.cardid";
            }

            // Date filtering
            DateTime dst = dateStart.Value;
            DateTime dfn = dateFinish.Value;
            string strdst = $"{dst:yyyy-MM-dd} {timeStart.Value:HH:mm:ss}";
            string strdfn = $"{dfn:yyyy-MM-dd} {timeFinish.Value:HH:mm:ss}";
            sql += $" WHERE dateout BETWEEN '{strdst}' AND '{strdfn}'";

            // User filter
            if (comUser.SelectedIndex > 0)
            {
                sql += $" AND recordout.userout = {dicUserInt[comUser.Text]}";
            }

            // Member group or type filter
            if (FormMain.pm.print.ReportSearchMemGroup)
            {
                if (comTypeMem.SelectedIndex > 0)
                    sql += $" AND member.memgroupid = {dicMemGroupInt[comTypeMem.Text]}";

                if (comType.SelectedIndex == 1)
                    sql += " AND recordin.cartype != 200";

                if (comType.SelectedIndex > 1)
                    sql += $" AND recordin.cartype = {dicCarTypeInt[comType.Text]}";
            }
            else if (FormMain.pm.print.Member2Cartype)
            {
                if (comTypeMem.SelectedIndex == 0)
                {
                    if (comType.SelectedIndex > 0)
                    {
                        sql += $" AND (recordin.cartype = {dicCarTypeInt[comType.Text]} OR member.typeid = {dicCarTypeInt[comType.Text]})";
                    }
                }
                else if (comTypeMem.SelectedIndex == 1)
                {
                    sql += " AND recordin.cartype != 200";
                    if (comType.SelectedIndex > 0)
                        sql += $" AND recordin.cartype = {dicCarTypeInt[comType.Text]}";
                }
                else if (comTypeMem.SelectedIndex == 2)
                {
                    sql += " AND recordin.cartype = 200";
                    if (comType.SelectedIndex > 0)
                        sql += $" AND member.typeid = {dicCarTypeInt[comType.Text]}";
                }
                else
                {
                    sql += $" AND member.memgroupid = {dicMemGroupInt[comTypeMem.Text]}";
                    if (comType.SelectedIndex > 0)
                        sql += $" AND member.typeid = {dicCarTypeInt[comType.Text]}";
                }
            }
            else
            {
                if (comType.SelectedIndex == 1)
                    sql += " AND recordin.cartype != 200";

                if (comType.SelectedIndex > 1)
                    sql += $" AND recordin.cartype = {dicCarTypeInt[comType.Text]}";

                if (comType.SelectedIndex == 0 && comTypeMem.SelectedIndex > 0)
                    sql += $" AND member.typeid = {dicCarTypeInt[comTypeMem.Text]}";
            }

            // License filter
            if (!string.IsNullOrWhiteSpace(txtLicense.Text))
                sql += $" AND recordin.license LIKE '%{txtLicense.Text}%'";

            // Card ID filter
            if (!string.IsNullOrWhiteSpace(txtCardID.Text))
                sql += $" AND recordin.id = {txtCardID.Text}";

            sql += " ORDER BY recordout.no";

            return sql;
        }

        private void CaseReportGroupPrice()
        {
            dgvResult.Columns[0].HeaderText = "เลขที่ใบเสร็จรับเงิน";
            dgvResult.Columns[1].HeaderText = "ทะเบียน";
            dgvResult.Columns[2].HeaderText = "เวลาเข้า";
            dgvResult.Columns[3].HeaderText = "เจ้าหน้าที่ขาเข้า";
            dgvResult.Columns[4].HeaderText = "เวลาออก";
            dgvResult.Columns[5].HeaderText = "เจ้าหน้าที่ขาออก";
            dgvResult.Columns[6].HeaderText = "ไม่ได้ E-stamp";
            dgvResult.Columns[7].HeaderText = "ได้ E-stamp แบบที่1 ฟรี 2 ชั่วโมง";
            dgvResult.Columns[8].HeaderText = "ได้ E-stamp แบบที่2 ฟรี 3 ชั่วโมง";

            dgvResult.Columns[9].HeaderText = "ค่าบริการจอด";
            dgvResult.Columns[10].HeaderText = "ยอดภาษี";
            dgvResult.Columns[11].HeaderText = "รายได้รวม";
            dgvResult.Columns[12].HeaderText = "ชื่อโปรโมชั่น";
            dgvResult.Columns[0].Width = 100;
            dgvResult.Columns[3].Width = 160;
            dgvResult.Columns[5].Width = 160;
            dgvResult.Columns[7].Width = 110;
            dgvResult.Columns[8].Width = 110;
            dgvResult.Columns[12].Width = 170;

            int intNo = dgvResult.Rows.Count - 1;

            int intSumR = 0;

            int intSumE0 = 0;
            int intSumE1 = 0;
            int intSumE2 = 0;

            double intSumBV = 0;
            double intSumV = 0;

            for (int i = 0; i < intNo; i++)
            {

                try
                {
                    int intGtype = Convert.ToInt32(dgvResult[11, i].Value);
                    int intT = Convert.ToInt32(dgvResult[6, i].Value);
                    int intD = Convert.ToInt32(dgvResult[7, i].Value);
                    int intR = intT + intD;
                    //int intID = Convert.ToInt32(dgvResult[1, i].Value);
                    //dgvResult[1, i].Value = dicCarTypeStr[intID];
                    DateTime dto = DateTime.Parse(dgvResult[4, i].Value.ToString());
                    dto = dto.AddYears(-543);
                    string strdto = dto.ToString("yyyyMM") + dgvResult[0, i].Value;
                    dgvResult[0, i].Value = strdto;

                    int intID = Convert.ToInt32(dgvResult[3, i].Value);
                    if (intID == 0)
                        dgvResult[3, i].Value = "";
                    else if (intID > 100 && intID < 104)
                        dgvResult[3, i].Value = dicDispenser[intID];
                    else
                        dgvResult[3, i].Value = dicUserStr[intID];

                    intID = Convert.ToInt32(dgvResult[5, i].Value);
                    if (intID == 0)
                        dgvResult[5, i].Value = "";
                    else if (intID > 100 && intID < 104)
                        dgvResult[3, i].Value = dicDispenser[intID];
                    else
                        dgvResult[5, i].Value = dicUserStr[intID];

                    //DateTime dti = DateTime.Parse(dgvResult[3, i].Value.ToString());
                    //DateTime dto = DateTime.Parse(dgvResult[5, i].Value.ToString());
                    //TimeSpan diffTime = dto - dti;
                    //int intHour = diffTime.Hours;
                    //if (diffTime.Days > 0)
                    //    intHour += diffTime.Days * 24;
                    //dgvResult[6, i].Value = intHour.ToString() + "." + diffTime.Minutes.ToString();

                    if (intGtype == 0)
                    {
                        dgvResult[6, i].Value = intR.ToString("#0.00");
                        dgvResult[7, i].Value = "";
                        dgvResult[8, i].Value = "";
                        intSumE0 += intR;
                    }
                    else if (intGtype == 1)
                    {
                        dgvResult[6, i].Value = "";
                        dgvResult[7, i].Value = intR.ToString("#0.00");
                        dgvResult[8, i].Value = "";
                        intSumE1 += intR;
                    }
                    else if (intGtype == 2)
                    {
                        dgvResult[6, i].Value = "";
                        dgvResult[7, i].Value = "";
                        dgvResult[8, i].Value = intR.ToString("#0.00");
                        intSumE2 += intR;
                    }
                    else if (intGtype == 200)
                    {
                        dgvResult[6, i].Value = "";
                        dgvResult[7, i].Value = "";
                        dgvResult[8, i].Value = "";
                        intSumE2 += intR;
                    }
                    intSumR += intR;

                    float floT = (float)intT;
                    double floBV = (floT * 100) / 107;
                    floBV = Math.Round(floBV, 2);
                    double floV = floT - floBV;
                    dgvResult[9, i].Value = floBV.ToString("#0.00");
                    dgvResult[10, i].Value = floV.ToString("#0.00");
                    dgvResult[11, i].Value = intR.ToString("#0.00");
                    intSumBV += floBV;
                    intSumV += floV;
                    string strProname = "";
                    intGtype = Convert.ToInt32(dgvResult[12, i].Value);

                    if (intGtype > 0)
                        strProname = dicProNameStr[intGtype];
                    dgvResult[12, i].Value = strProname;
                }
                catch (Exception)
                {
                }
            }

            dgvResult[3, intNo].Value = "จำนวนรถ";
            dgvResult[4, intNo].Value = intNo.ToString() + " คัน";
            dgvResult[5, intNo].Value = "ยอดรวม";
            dgvResult[6, intNo].Value = intSumE0.ToString("#0.00");
            dgvResult[7, intNo].Value = intSumE1.ToString("#0.00");
            dgvResult[8, intNo].Value = intSumE2.ToString("#0.00");
            dgvResult[9, intNo].Value = intSumBV.ToString("#0.00");
            dgvResult[10, intNo].Value = intSumV.ToString("#0.00");
            dgvResult[11, intNo].Value = intSumR.ToString("#0.00");
        }

