            int intSumPrice = 0;
            int intSumPriceLoss = 0;
            int intSumPriceOver = 0;
            int intSumDiscount = 0; //Mac 2016/03/05
            double doubleSumBeforeVat = 0;
            double doubleSumVat = 0;


            for (int i = 0; i < intNo; i++)
            {
