                            else
                                dgvResult[0, i].Value = "IV" + dto.ToString("yy") + intID.ToString("00000#");*/
                            dgvResult[0, i].Value = fontSlip13 + dto.ToString("yy") + intID.ToString("00000#"); //Mac 2018/05/13
