                        }
                        else
                        {
                            dgvResult[9, i].Value = intHour.ToString();//ลด
                            dgvResult[10, i].Value = "0";//จ่าย
                        }
                    }
                    else
                    {
                        //if (intSelectedIndex == 13) intID = Convert.ToInt32(dgvResult[16, i].Value);
                        //Mac 2018/02/23
                        if (intSelectedIndex == 13 && !pm.print.UseReport14like13) intID = Convert.ToInt32(dgvResult[16, i].Value); //Mac 2018/02/23
                        else intID = Convert.ToInt32(dgvResult[15, i].Value); //Mac 2016/03/05
