                        dgvResult[14, i].Value = vat.ToString("#0.0000");*/
                        doubleSumBeforeVat += beforeVat;
                        doubleSumVat += vat;
                    }
                    catch (Exception) { }
                }


                intSumPriceLoss += Convert.ToInt32(dgvResult[11, i].Value);
                if (intSelectedIndex == 12 && pm.print.UseReport13_11) //Mac 2017/11/30
