                        dgvResult[10, i].Value = "0";
                }
            }
            dgvResult[5, intNo].Value = "จำนวนรถ";
            dgvResult[6, intNo].Value = intNo.ToString("#,###,##0") + " คัน";
            //dgvResult[6, intNo].Value = intNo + " คัน";
            dgvResult[10, intNo].Value = "รายได้รวม";
            dgvResult[11, intNo].Value = intSumPriceLoss.ToString("#,###,##0");
            dgvResult[12, intNo].Value = intSumPriceOver.ToString("#,###,##0");
            /*dgvResult[11, intNo].Value = intSumPriceLoss;
            dgvResult[12, intNo].Value = intSumPriceOver;*/
            //if (intSelectedIndex == 13)
            if (intSelectedIndex == 13 && !pm.print.UseReport14like13) //Mac 2018/02/24
            {
                if (pm.print.UseCalVatFromTotal) //Mac 2022/09/30
                {
                    dgvResult[13, intNo].Value = (Convert.ToDouble(intSumPrice) - (Convert.ToDouble(intSumPrice) * 7 / 107)).ToString("#,###,##0.00");
                    dgvResult[14, intNo].Value = (Convert.ToDouble(intSumPrice) * 7 / 107).ToString("#,###,##0.00");
                    dgvResult[15, intNo].Value = intSumPrice.ToString("#,###,##0");
                }
                else
                {
                    if (pm.print.Report3Decimal) //Mac 2016/10/06
                    {
                        dgvResult[13, intNo].Value = doubleSumBeforeVat.ToString("#,###,##0.000");
                        dgvResult[14, intNo].Value = doubleSumVat.ToString("#,###,##0.000");
                        //dgvResult[15, intNo].Value = intSumPrice.ToString("#,###,##0.000");
                    }
                    else
                    {
                        dgvResult[13, intNo].Value = doubleSumBeforeVat.ToString("#,###,##0.00");
                        dgvResult[14, intNo].Value = doubleSumVat.ToString("#,###,##0.00");
                        //dgvResult[15, intNo].Value = intSumPrice.ToString("#,###,##0.00");
                    }
                    dgvResult[15, intNo].Value = intSumPrice.ToString("#,###,##0");
                }
                /*dgvResult[13, intNo].Value = doubleSumBeforeVat.ToString("#0.0000");
                dgvResult[14, intNo].Value = doubleSumVat.ToString("#0.0000"); ;
                dgvResult[15, intNo].Value = intSumPrice;*/
            }
            else
            {
                dgvResult[13, intNo].Value = intSumPrice.ToString("#,###,##0");
                dgvResult[14, intNo].Value = intSumDiscount.ToString("#,###,##0"); //Mac 2016/03/05
            }
            //else dgvResult[13, intNo].Value = intSumPrice;
            //      
            tl = intSumPriceLoss;
            to = intSumPriceOver;
            tp = intSumPrice;
            td = intSumDiscount; //Mac 2016/03/05
            tb = doubleSumBeforeVat;
            tv = doubleSumVat;

            if (pm.print.UseReceiptFor1Out) //Mac 2018/11/14
                dgvResult.Columns[dgvResult.ColumnCount - 1].Visible = false;
        }

