                int intID = Convert.ToInt32(dgvResult[0, i].Value);
                DateTime dto = DateTime.Parse(dgvResult[7, i].Value.ToString());
                if (intID > 0)
                {
                    string fontSlip13 = "";
                    if (strReceiptName.Length > 0)
                        fontSlip13 = strReceiptName;
                    else
                    {
                        if (!UsestrReceiptName)
                            fontSlip13 = "IV";
                    }

                    if (pm.print.UseReceiptFor1Out)
                    {
                        if (pm.print.OutReceiptNameMonth)
                        {
                            dgvResult[0, i].Value = dgvResult[dgvResult.ColumnCount - 1, i].Value.ToString() + dto.ToString("yyMM") + intID.ToString("00000#"); //Mac 2022/04/26
                        }
                        else
                        {
                            dgvResult[0, i].Value = dgvResult[dgvResult.ColumnCount - 1, i].Value.ToString() + dto.ToString("yy") + intID.ToString("00000#");
                        }
                    }
                    else
                    {
                        if (pm.print.OutReceiptNameMonth)
                        {
                            dgvResult[0, i].Value = fontSlip13 + dto.ToString("yyMM") + intID.ToString("00000#");
                        }
                        else
                        {
                            dgvResult[0, i].Value = fontSlip13 + dto.ToString("yy") + intID.ToString("00000#");
                        }
                    }
                }

                try
                {
                    string x = dgvResult[3, i].Value.ToString();
                    int value;
                    if (int.TryParse(x, out value))
                    {
                        intID = value;
                        dgvResult[3, i].Value = dicCarTypeStr[intID];
                    }
                    else
                        dgvResult[3, i].Value = x;
                }
                catch
                {
                    dgvResult[3, i].Value = "";
                }


                try
                {
                    intID = Convert.ToInt32(dgvResult[6, i].Value);
                    if (intID == 0)
                        dgvResult[6, i].Value = "";
                    else
                        dgvResult[6, i].Value = dicUserStr[intID];
                }
                catch
                {
                    dgvResult[6, i].Value = "";
                }

                DateTime dti = DateTime.Parse(dgvResult[5, i].Value.ToString());
                TimeSpan diffTime = dto - dti;
                int intHour = diffTime.Hours;
                if (diffTime.Days > 0)
                    intHour += diffTime.Days * 24;
                if (diffTime.Minutes > 0)
                    intHour++;
                dgvResult[8, i].Value = intHour.ToString();

                string totalInOut = "";
                if (diffTime.Days == 0 && diffTime.Hours == 0 && diffTime.Minutes == 0)
                    totalInOut = "0";
                else
                    totalInOut = (diffTime.Days * 24) + diffTime.Hours + "." + diffTime.Minutes.ToString("00");

                dgvResult[8, i].Value = totalInOut;

                try
                {
                    if (pm.print.UseProIDAll)
                    {
                        string[] ProIDAll;
                        int intHourPro = 0;

                        if (intSelectedIndex == 13 && !pm.print.UseReport14like13)
                        {
                            ProIDAll = dgvResult[17, i].Value.ToString().Split(',');
                            dgvResult[17, i].Value = "";
                        }
                        else
                        {
                            ProIDAll = dgvResult[16, i].Value.ToString().Split(',');
                            dgvResult[16, i].Value = "";
                        }

                        for (int n = 0; n < ProIDAll.Length; n++)
                        {
                            if (ProIDAll[n].Length > 0)
                            {
                                intHourPro += dicProNameMinute[Convert.ToInt16(ProIDAll[n])];

                                if (intSelectedIndex == 13 && !pm.print.UseReport14like13)
                                    dgvResult[17, i].Value += dicProNameStr[Convert.ToInt16(ProIDAll[n])];
                                else
                                    dgvResult[16, i].Value += dicProNameStr[Convert.ToInt16(ProIDAll[n])];

                                if (n < (ProIDAll.Length - 2))
                                {
                                    if (intSelectedIndex == 13 && !pm.print.UseReport14like13)
                                        dgvResult[17, i].Value += "|";
                                    else
                                        dgvResult[16, i].Value += "|";
                                }

                            }
                        }

                        intHourPro = intHourPro / 60;

                        dgvResult[9, i].Value = intHourPro.ToString();
                        if (intHourPro < intHour)
                        {
                            dgvResult[10, i].Value = intHourPro.ToString();
                            dgvResult[11, i].Value = (intHour - intHourPro).ToString();
                        }
                        else
                        {
                            dgvResult[10, i].Value = intHour.ToString();
                            dgvResult[11, i].Value = "0";
                        }
                    }
                    else
                    {
                        if (intSelectedIndex == 13 && !pm.print.UseReport14like13) intID = Convert.ToInt32(dgvResult[17, i].Value);
                        else intID = Convert.ToInt32(dgvResult[16, i].Value);

                        int intHourPro = 0;
                        if (intID > 0)
                            intHourPro = dicProNameMinute[intID] / 60;
                        dgvResult[9, i].Value = intHourPro.ToString();
                        if (intHourPro < intHour)
                        {
                            dgvResult[10, i].Value = intHourPro.ToString();
                            dgvResult[11, i].Value = (intHour - intHourPro).ToString();
                        }
                        else
                        {
                            dgvResult[10, i].Value = intHour.ToString();
                            dgvResult[11, i].Value = "0";
                        }

                        if (intID > 0)
                        {

                            if (intSelectedIndex == 13 && !pm.print.UseReport14like13) dgvResult[17, i].Value = dicProNameStr[intID];
                            else dgvResult[16, i].Value = dicProNameStr[intID];
                        }
                        else
                        {
                            if (intSelectedIndex == 13 && !pm.print.UseReport14like13) dgvResult[17, i].Value = "";
                            else dgvResult[16, i].Value = "";
                        }
                    }
                }
                catch
                {
                    dgvResult[9, i].Value = "0";
                    dgvResult[10, i].Value = "0";
                    dgvResult[11, i].Value = "0";

                    if (intSelectedIndex == 13 && !pm.print.UseReport14like13)
                        dgvResult[17, i].Value = "";
                    else
                        dgvResult[16, i].Value = "";
                }

                if (intSelectedIndex == 13 && !pm.print.UseReport14like13)
                {
                    try
                    {
                        double vat = (double.Parse(dgvResult[16, i].Value.ToString()) * 7) / 107;

                        if (pm.print.Report3Decimal)
                            vat = Math.Round(vat, 3);
                        else
                            vat = Math.Round(vat, 2);

                        double beforeVat = double.Parse(dgvResult[16, i].Value.ToString()) - vat;

                        if (pm.print.Report3Decimal)
                        {
                            dgvResult[14, i].Value = beforeVat.ToString("#,###,##0.000");
                            dgvResult[15, i].Value = vat.ToString("#,###,##0.000");
                        }
                        else
                        {
                            dgvResult[14, i].Value = beforeVat.ToString("#,###,##0.00");
                            dgvResult[15, i].Value = vat.ToString("#,###,##0.00");
                        }

                        doubleSumBeforeVat += beforeVat;
                        doubleSumVat += vat;
                    }
                    catch (Exception) { }
                }


                intSumPriceLoss += Convert.ToInt32(dgvResult[12, i].Value);
                if (intSelectedIndex == 12 && pm.print.UseReport13_11)
                {

                }
                else
                    intSumPriceOver += Convert.ToInt32(dgvResult[13, i].Value);

                if (intSelectedIndex == 13 && !pm.print.UseReport14like13)
                {
                    intSumPrice += Convert.ToInt32(dgvResult[16, i].Value);

                    if (Convert.ToInt32(dgvResult[16, i].Value) == 0)
                        dgvResult[11, i].Value = "0";

                    if (pm.print.UseReport13_3)
                    {
                        if (dgvResult[18, i].Value.ToString().Trim() == "")
                            dgvResult[18, i].Value = dgvResult[16, i].Value;
                    }
                }
                else
                {
                    intSumPrice += Convert.ToInt32(dgvResult[14, i].Value);
                    intSumDiscount += Convert.ToInt32(dgvResult[15, i].Value);

                    if (Convert.ToInt32(dgvResult[14, i].Value) == 0)
                        dgvResult[11, i].Value = "0";
                }
            }
            dgvResult[6, intNo].Value = "จำนวนรถ";
            dgvResult[7, intNo].Value = intNo.ToString("#,###,##0") + " คัน";
            dgvResult[11, intNo].Value = "รายได้รวม";
            dgvResult[12, intNo].Value = intSumPriceLoss.ToString("#,###,##0");
            dgvResult[13, intNo].Value = intSumPriceOver.ToString("#,###,##0");
            if (intSelectedIndex == 13 && !pm.print.UseReport14like13)
            {
                if (pm.print.UseCalVatFromTotal)
                {
                    dgvResult[14, intNo].Value = (Convert.ToDouble(intSumPrice) - (Convert.ToDouble(intSumPrice) * 7 / 107)).ToString("#,###,##0.00");
                    dgvResult[15, intNo].Value = (Convert.ToDouble(intSumPrice) * 7 / 107).ToString("#,###,##0.00");
                    dgvResult[16, intNo].Value = intSumPrice.ToString("#,###,##0");
                }
                else
                {
                    if (pm.print.Report3Decimal)
                    {
                        dgvResult[14, intNo].Value = doubleSumBeforeVat.ToString("#,###,##0.000");
                        dgvResult[15, intNo].Value = doubleSumVat.ToString("#,###,##0.000");
                    }
                    else
                    {
                        dgvResult[14, intNo].Value = doubleSumBeforeVat.ToString("#,###,##0.00");
                        dgvResult[15, intNo].Value = doubleSumVat.ToString("#,###,##0.00");
                    }
                    dgvResult[16, intNo].Value = intSumPrice.ToString("#,###,##0");
                }
            }
            else
            {
                dgvResult[14, intNo].Value = intSumPrice.ToString("#,###,##0");
                dgvResult[15, intNo].Value = intSumDiscount.ToString("#,###,##0");
            }

            tl = intSumPriceLoss;
            to = intSumPriceOver;
            tp = intSumPrice;
            td = intSumDiscount;
            tb = doubleSumBeforeVat;
            tv = doubleSumVat;

            if (pm.print.UseReceiptFor1Out)
                dgvResult.Columns[dgvResult.ColumnCount - 1].Visible = false;
        }

