                    iVil += 4;
                if (pm.print.UseReport1_6 || pm.print.UseReport1_8)
                    iVil = 1;

                if (pm.Use2Camera)
                {
                    HandleTwoCameraReport(rowIndex, iVil);
                }
                else
                {
                    HandleSingleCameraReport(rowIndex, iVil);
                }
            }
            else if (intSelectedIndex == 7 || intSelectedIndex == 31 || intSelectedIndex == 93)
            {
                string pic1, pic2;
                pic1 = dgvResult.Rows[e.RowIndex].Cells["picdiv"].Value.ToString();

                if (pic1.Trim() != "" || pic1 != null)
