        public void ExportToExcel(DataGridView Tbl, string ExcelFilePath = null)
        {
            try
            {
                if (Tbl == null || Tbl.Columns.Count == 0)
                    throw new Exception("ExportToExcel: Null or empty input table!\n");

                // load excel, and create a new workbook
                Excel.Application excelApp = new Excel.Application();
                excelApp.Workbooks.Add();

                // single worksheet
                Excel._Worksheet workSheet = excelApp.ActiveSheet;

                // heading report
                workSheet.Cells[1, 1] = strHead;

                // column headings
                for (int i = 0; i < Tbl.Columns.Count; i++)
                {
                    workSheet.Cells[2, (i + 1)] = Tbl.Columns[i].HeaderText;
                }

                // rows
                for (int i = 0; i < Tbl.Rows.Count; i++)
                {
                    // to do: format datetime values before printing
                    for (int j = 0; j < Tbl.Columns.Count; j++)
                    {
                        //workSheet.Cells[(i + 3), (j + 1)] = "'" + Tbl.Rows[i].Cells[j].Value;
                        if ((Tbl.Columns[j].HeaderText.Length > 2) && (Tbl.Columns[j].HeaderText.Substring(0, 3) == "วัน") && (pm.print.UseReportDateString)) //Mac 2018/07/05
                        {
                            workSheet.Cells[(i + 3), (j + 1)].NumberFormat = "@";
                        }
                        else if ((Tbl.Columns[j].HeaderText.Length > 3) && (Tbl.Columns[j].HeaderText.Substring(0, 4) == "เวลา") && (pm.print.UseReportDateString)) //Mac 2017/11/25
                        {
                            //workSheet.Cells[(i + 3), (j + 1)].NumberFormat = "dd/mm/yyyy hh:mm:ss;@";
                            workSheet.Cells[(i + 3), (j + 1)].NumberFormat = "@";
                        }
                        else if ((Tbl.Columns[j].HeaderText.Length > 3) && (Tbl.Columns[j].HeaderText.Substring(0, 4) == "ว.ด.") && (pm.print.UseReportDateString)) //Mac 2018/12/22
                        {
                            workSheet.Cells[(i + 3), (j + 1)].NumberFormat = "@";
                        }


                        workSheet.Cells[(i + 3), (j + 1)] = Tbl.Rows[i].Cells[j].Value;
                    }
                }
                /*// sum
                for (int i = 0; i < Tbl.Columns.Count; i++)
                {
                    if (dgvResult.Rows[dgvResult.Rows.Count - 1].Cells[i].Value != null || dgvResult.Rows[dgvResult.Rows.Count - 1].Cells[i].Value == "")
                        workSheet.Cells[(Tbl.Rows.Count + 3), (i + 1)] = dgvResult.Rows[dgvResult.Rows.Count - 1].Cells[i].Value.ToString();
                }*/

                // check fielpath
                if (ExcelFilePath != null && ExcelFilePath != "")
                {
                    try
                    {
                        workSheet.SaveAs(ExcelFilePath);
                        excelApp.Quit();
                        MessageBox.Show("Excel file saved!");
                    }
                    catch (Exception ex)
                    {
                        throw new Exception("ExportToExcel: Excel file could not be saved! Check filepath.\n"
                            + ex.Message);
                    }
                }
                else    // no filepath is given
                {
                    excelApp.Visible = true;
                }
            }
            catch (Exception ex)
            {
                //throw new Exception("ExportToExcel: \n" + ex.Message);
            }
        }

