        private void ToText(DataTable dt, string filename)
        {
            string stOutput = "";
            // Export data.
            for (int i = 0; i < dt.Rows.Count; i++)
            {
                string stLine = "";
                for (int j = 0; j < dt.Columns.Count; j++)
                {
                    if (j == (dt.Columns.Count - 1))
                        stLine = stLine.ToString() + Convert.ToString(dt.Rows[i].ItemArray[j].ToString());
                    else
                        stLine = stLine.ToString() + Convert.ToString(dt.Rows[i].ItemArray[j].ToString()) + ",";
                }
                stOutput += stLine + "\r\n";
            }
            //Encoding utf8 = Encoding.GetEncoding(1254);
            Encoding utf8 = Encoding.GetEncoding("TIS-620");
            byte[] output = utf8.GetBytes(stOutput);

            FileStream fs = new FileStream(filename, FileMode.Create);
            BinaryWriter bw = new BinaryWriter(fs);
            bw.Write(output, 0, output.Length); //write the encoded file
            bw.Flush();
            bw.Close();
            fs.Close();
            MessageBox.Show("Text file Save Complete!");
        }

        private void ToCsV(DataGridView dGV, string filename)
        {
            string stOutput = strHead + "\r\n"; // Header
            if (intSelectedIndex == 13)
            {
                stOutput = dicParam["com1"].Trim() + "\r\n"
                + "รายงานภาษีขายสำหรับรายได้ค่าบริการที่จอดรถ\r\n"
                + strHead + "\r\n";
            }
            // Export titles:
            string sHeaders = "";

            for (int j = 0; j < dGV.Columns.Count; j++)
                if (Convert.ToString(dGV.Columns[j].HeaderText) == "เลขที่ใบเสร็จ/ใบกำกับภาษี")
                    sHeaders = sHeaders.ToString() + "เลขที่ใบเสร็จ/ใบกำกับภาษีอย่างย่อ" + ",";
                else
                    sHeaders = sHeaders.ToString() + Convert.ToString(dGV.Columns[j].HeaderText) + ",";
            stOutput += sHeaders + "\r\n";
            // Export data.
            for (int i = 0; i < dGV.RowCount; i++)// - 1
            {
                string stLine = "";
                for (int j = 0; j < dGV.Rows[i].Cells.Count; j++)
                    stLine = stLine.ToString() + Convert.ToString(dGV.Rows[i].Cells[j].Value) + ",";
                stOutput += stLine + "\r\n";
            }
            //Encoding utf8 = Encoding.GetEncoding(1254);
            Encoding utf8 = Encoding.GetEncoding("TIS-620");
            byte[] output = utf8.GetBytes(stOutput);

            FileStream fs = new FileStream(filename, FileMode.Create);
            BinaryWriter bw = new BinaryWriter(fs);
            bw.Write(output, 0, output.Length); //write the encoded file
            bw.Flush();
            bw.Close();
            fs.Close();
        }

