        private void removeTab(string name)
        {
            for (int i = 0; i < tabControl1.TabPages.Count; i++)
            {
                if (tabControl1.TabPages[i].Name.Equals(name, StringComparison.OrdinalIgnoreCase))
                {
                    tabControl1.TabPages.RemoveAt(i);
                    break;
                }
            }
        }

        private void saveUser()
        {
            // Save
            string sql;

            if (strIdUser != "")
            {
                sql = "update user SET cardname = '" + txtCard.Text + "',"
                    + " level = '" + txtLevel.Text + "',"
                    + " username = '" + txtUsername.Text + "',"
                    + " password = '" + txtPassword.Text + "',"
                    + " name = '" + txtName.Text + "',"
                    + " address = '" + txtAddress.Text + "',"
                    + " tel = '" + txtTel.Text + "',";
                if (txtGroup.Text.Trim() != "")
                    sql += " grouprpt =" + txtGroup.Text;
                else sql += " grouprpt = NULL";
                sql += "  where id = " + strIdUser;
                Console.WriteLine(sql);
                if (pm.SaveData(sql) == "")
                {
                    MessageBox.Show("บันทึกการแก้ไขข้อมูลเรียบร้อย");
                }
                else MessageBox.Show("บันทึกไม่สำเร็จ");
            }
            else
            {
                sql = "INSERT INTO user (cardname,level,username,password,name,address,tel,grouprpt)";
                sql += "VALUES ('" + txtCard.Text + "',"
                    + "'" + txtLevel.Text + "',"
                    + "'" + txtUsername.Text + "',"
                    + "'" + txtPassword.Text + "',"
                    + "'" + txtName.Text + "',"
                    + "'" + txtAddress.Text + "',"
                    + "'" + txtTel.Text + "',";
                if (txtGroup.Text.Trim() != "")
                    sql += " grouprpt =" + txtGroup.Text + ")";
                else sql += " grouprpt = NULL)";
                if (pm.SaveData(sql) == "")
                {
                    MessageBox.Show("บันทึกการเพิ่มข้อมูลเรียบร้อย");
                }
                else MessageBox.Show("บันทึกไม่สำเร็จ");
            }
            dgvUser.DataSource = null;
            sql = "select * from user";
            DataTable dt = pm.LoadData(sql);
            dgvUser.DataSource = dt;
            clearUser();
        }

