        //bool UseNoDay >> Tabel - Param /Field - not_day
        int[] intTime;
        int[] intPriceMin;
        int[] intPriceHour;
        int[] intHourRound;
        int[] intExpense;
        int[] intOver;

        //Mac 2022/07/26
        int FlatRateM = 0;
        int FlatRateP = 0;
        int FlatRateX = 0;

        public int CalPrice(int intHour, int intMin, bool UseNoDay)
        {

            int intPrice = 0;

            intMin += intHour * 60;

            int intDay = 1;
            if (!UseNoDay)
            {
                if (intMin > 1440)
                {
                    intDay = (intMin / 1440) + 1;
                }
            }

            int intMinDay = 0;
            for (int d = 0; d < intDay; d++)
            {
                int intMinCal = 0;
                int intHourCal = 0;

                if (!UseNoDay)
                {
                    if (intMin > 1440)
                    {
                        intMinDay = 1440;
                        intMin = intMin - 1440;
                    }
                    else
                    {
                        intMinDay = intMin;
                        intMin = 0;
                    }
                }
                else
                {
                    intMinDay = intMin;
                }

                int intPriceB = intPrice;

                for (int i = 0; i < intTime.Count(); i++)
                {
                    if (intMinDay > intTime[i])
                    {
                        intMinCal = intTime[i];
                        intMinDay = intMinDay - intMinCal;
                    }
                    else
                    {
                        intMinCal = intMinDay;
                        intMinDay = 0;
                    }

                    if (UseNoDay)
                    {
                        intPriceB += intMinCal;
                        if (intPriceB >= 1440)
                        {
                            intMinCal += intMinDay;
                            intMinDay = 0;
                        }
                    }

                    if (intPriceMin[i] > 0)
                    {
                        intPrice += intPriceMin[i] * intMinCal;
                    }
                    else if (intPriceHour[i] > 0)
                    {
                        if (intMinCal > 60)
                        {
                            intHourCal = intMinCal / 60;
                            intMinCal = intMinCal - (intHourCal * 60);
                        }
                        if (intMinCal >= intHourRound[i])
                            intHourCal++;
                        intPrice += intPriceHour[i] * intHourCal;
                        intHourCal = 0;
                    }
                    else if (intExpense[i] > 0)
                    {
                        intPrice += intExpense[i];
                    }

                    if (intOver[i] > 0 && intMinDay > 0)
                    {
                        intPrice = intPriceB + intOver[i];
                        intMinDay = 0;
                    }
                    if (intMinDay < 1)
                        break;
                }
            }
            if (intPrice < 0)
                intPrice = 0;
            return intPrice;
        }

