        private void btnUpdateReport_Click(object sender, EventArgs e)
        {
            string sql = "";
            double num;
            string datein = "";
            string dateout = "";

            for (int i = 0; i < dgvResult.Rows.Count - 1; i++)
            {
                try
                {
                    if (intSelectedIndex == 12) //Mac 2016/04/26
                    {
                        if (double.TryParse(dgvResult.Rows[i].Cells[15].Value.ToString(), out num))
                        {
                            sql = "update recordout set proid = " + dgvResult.Rows[i].Cells[15].Value;
                            sql += " where no = " + dgvResult.Rows[i].Cells[1].Value;
                            pm.SaveData(sql);
                        }

                    }
                    else
                    {
                        /*if (double.TryParse(dgvResult.Rows[i].Cells[14].Value.ToString(), out num))
                        {*/
                        /*datein = dgvResult.Rows[i].Cells[4].Value.ToString().Substring(6, 4) + "-" + dgvResult.Rows[i].Cells[4].Value.ToString().Substring(3, 2) + "-";
                        datein += dgvResult.Rows[i].Cells[4].Value.ToString().Substring(0, 2) + " " + dgvResult.Rows[i].Cells[4].Value.ToString().Substring(11);
                        dateout = dgvResult.Rows[i].Cells[6].Value.ToString().Substring(6, 4) + "-" + dgvResult.Rows[i].Cells[6].Value.ToString().Substring(3, 2) + "-";
                        dateout += dgvResult.Rows[i].Cells[6].Value.ToString().Substring(0, 2) + " " + dgvResult.Rows[i].Cells[6].Value.ToString().Substring(11);*/

                        datein = dgvResult.Rows[i].Cells[2].Value + ":00";
                        dateout = dgvResult.Rows[i].Cells[3].Value + ":00";
                        sql = "UPDATE recordin t1 LEFT JOIN recordout t2 ON t1.no = t2.no ";
                        /*sql += " SET t1.datein = '" + datein + "', ";
                        sql += " t2.dateout = '" + dateout + "', ";*/

                        sql += " SET t1.datein = concat(left(t1.datein, 11),'" + datein + "')";
                        sql += " , t2.dateout = concat(left(t2.dateout, 11),'" + dateout + "')";
                        sql += " , t1.license = " + dgvResult.Rows[i].Cells[4].Value;
                        sql += " , t2.proid = " + dgvResult.Rows[i].Cells[5].Value;
                        sql += " , t2.price = " + dgvResult.Rows[i].Cells[6].Value;
                        sql += " WHERE t2.no = " + dgvResult.Rows[i].Cells[0].Value;
                        pm.SaveData(sql);
                    }
                }
                catch
                {

                }
                //}
            }
            MessageBox.Show("Update complete", "", MessageBoxButtons.OK, MessageBoxIcon.Information);
            dgvResult.DataSource = null;
        }

