        private void dgvResultAtRunning()
        {
            //if (intSelectedIndex == 0 || intSelectedIndex == 1 || intSelectedIndex == 2 || intSelectedIndex == 3 || intSelectedIndex == 4 || intSelectedIndex == 5 || intSelectedIndex == 12 || intSelectedIndex == 13 || intSelectedIndex == 30 || intSelectedIndex == 31 || intSelectedIndex == 8 || intSelectedIndex == 79)
            if (intSelectedIndex == 0 || intSelectedIndex == 1 || intSelectedIndex == 2 || intSelectedIndex == 3 || intSelectedIndex == 4 || intSelectedIndex == 5 || intSelectedIndex == 12 || intSelectedIndex == 13 || intSelectedIndex == 30 || intSelectedIndex == 31 || intSelectedIndex == 8 || intSelectedIndex == 79 || intSelectedIndex == 90 || intSelectedIndex == 91 || intSelectedIndex == 92 || intSelectedIndex == 93 || intSelectedIndex == 94 || intSelectedIndex == 10) //Mac 2020/10/26
            {
                if (this.dgvResult.RowCount > 0)
                {
                    foreach (DataGridViewRow r in this.dgvResult.Rows)
                    {
                        if (r.Index < dgvResult.RowCount - 1)
                            this.dgvResult.Rows[r.Index].HeaderCell.Value = (r.Index + 1).ToString();
                    }
                    this.dgvResult.AutoResizeRowHeadersWidth(DataGridViewRowHeadersWidthSizeMode.AutoSizeToAllHeaders);
                    this.dgvResult.TopLeftHeaderCell.Value = "ลำดับ";
                    if (intSelectedIndex == 12 || intSelectedIndex == 13)
                        this.dgvResult.Columns[1].Visible = false;
                    else
                        this.dgvResult.Columns[0].Visible = false;
                }
            }
            else
            {
                this.dgvResult.TopLeftHeaderCell.Value = "";
            }
        }

