        public int CalFlatRate(DateTime dti, DateTime dto, int M, int P, int X)
        {
            int Price = 0;
            int totalM = 0;
            TimeSpan diffInOut;

            if (M == 0)
                return 0;

            diffInOut = dto - dti;
            totalM = diffInOut.Minutes;
            totalM += diffInOut.Hours * 60;
            totalM += diffInOut.Days * 24 * 60;

            Price = ((totalM - X) / M) * P;

            return Price;
        }

        private void HandleTwoCameraReport(int rowIndex, int columnOffset)
        {
            string pic1 = dgvResult.Rows[rowIndex].Cells["iv"].Value.ToString();
            string pic2 = dgvResult.Rows[rowIndex].Cells["il"].Value.ToString();
            string pic3 = dgvResult.Rows[rowIndex].Cells["ov"].Value.ToString();
            string pic4 = dgvResult.Rows[rowIndex].Cells["ol"].Value.ToString();

            SetImageSourceToPictureBox(pic1, pictureBox1);
            SetImageSourceToPictureBox(pic2, pictureBox2);
            SetImageSourceToPictureBox(pic3, pictureBox3);
            SetImageSourceToPictureBox(pic4, pictureBox4);

            HandleAdditionalFifthImage(rowIndex, columnOffset);
        }

        private void HandleSingleCameraReport(int rowIndex, int columnOffset)
        {
            string pic1 = dgvResult.Rows[rowIndex].Cells["il"].Value.ToString();
            string pic2 = dgvResult.Rows[rowIndex].Cells["ol"].Value.ToString();

            SetImageSourceToPictureBox(pic1, pictureBox1);
            SetImageSourceToPictureBox(pic2, pictureBox2);
        }

        private void SetImageSourceToPictureBox(string imagePath, PictureBox pictureBox)
        {
            if (!string.IsNullOrEmpty(imagePath?.Trim()))
            {
                Image image = GetCopyImage(imagePath);
                pictureBox.Image = image;
            }
        }

        private void HandleAdditionalFifthImage(int rowIndex, int columnOffset)
        {
            bool shouldShowFifthImage = (village && pm.Use2Camera) ||
                                       (pm.Use2Camera && !string.IsNullOrEmpty(pm.IPIn3.Trim()));

            if (shouldShowFifthImage)
            {
                string pic5 = dgvResult.Rows[rowIndex].Cells[13 + columnOffset].Value.ToString();
                SetImageSourceToPictureBox(pic5, pictureBox5);
            }
        }
    }
